    .{ .name = "Africa/Johannesburg",         .std = 120,  .dst = 120,  .rule = 0 },
    .{ .name = "Africa/Lagos",                .std = 60,   .dst = 60,   .rule = 0 },
    .{ .name = "Atlantic/Azores",             .std = -60,  .dst = 0,    .rule = 2 },
    .{ .name = "Atlantic/Cape_Verde",         .std = -60,  .dst = -60,  .rule = 0 },
